final:
module RefModule (
    input A1,
    input A2,
    input B1,
    output Y
);

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire __A1_tmp = (A1 || (A2 && !A1) || (!A1 && !A2 && B1));
    assign Y = __A1_tmp ? 1'b1 : 1'b0;

endmodule
